    public void test_TC08() {
        // GIVEN an Element moved from oldParent to newParent
        Element oldParent = new Element("div");
        Element newParent = new Element("section");
        Element child = new Element("article");
        // first append to oldParent (ensures child has parent and siblingIndex 0)
        oldParent.appendChild(child);
        assertEquals(1, oldParent.childNodeSize(), "oldParent should have one child initially");
        // WHEN reparenting child to newParent via appendChild
        Element returned = newParent.appendChild(child);
        // THEN appendChild returns the same element (this), reparented with correct siblingIndex and sizes
        assertSame(newParent, returned, "appendChild should return the parent element for chaining");
        assertEquals(0, child.siblingIndex(), "child should have siblingIndex 0 in newParent");
        assertEquals(1, newParent.childNodeSize(), "newParent should now have exactly one child");
        assertEquals(0, oldParent.childNodeSize(), "oldParent should have no children after reparenting");
        assertSame(newParent, child.parent(), "child.parent() should point to newParent after reparenting");
    }
